import { urlAlphabet as scopedUrlAlphabet } from "./url-alphabet/index.js";

export { urlAlphabet } from "./url-alphabet/index.js";

export const random = (bytes) => crypto.getRandomValues(new Uint8Array(bytes));

export const customRandom = (alphabet, defaultSize, getRandom) => {
	const safeByteCutoff = 256 - (256 % alphabet.length);

	if (safeByteCutoff === 256) {
		const mask = alphabet.length - 1;

		return (size = defaultSize) => {
			if (!size) return "";
			let id = "";
			while (true) {
				const bytes = getRandom(size);
				let j = size;
				while (j--) {
					id += alphabet[bytes[j] & mask];
					if (id.length >= size) return id;
				}
			}
		};
	}

	const step = Math.ceil((1.6 * 256 * defaultSize) / safeByteCutoff);

	return (size = defaultSize) => {
		if (!size) return "";
		let id = "";
		while (true) {
			const bytes = getRandom(step);
			let j = step;
			while (j--) {
				if (bytes[j] < safeByteCutoff) {
					id += alphabet[bytes[j] % alphabet.length];
					if (id.length >= size) return id;
				}
			}
		}
	};
};

export const customAlphabet = (alphabet, size = 21) =>
	customRandom(alphabet, size | 0, random);

export const nanoid = (size = 21) => {
	let id = "";
	const bytes = crypto.getRandomValues(new Uint8Array((size |= 0)));
	while (size--) {
		id += scopedUrlAlphabet[bytes[size] & 63];
	}
	return id;
};
